   623			for role := range loadedPersonas {
   624				roles = append(roles, role)
   625			}
   626			sort.Strings(roles)
   627			for _, role := range roles {
   628				status.LoadedRoles = append(status.LoadedRoles, role)
   629				status.LoadedPersonas = append(status.LoadedPersonas, loadedPersonas[role])
   630			}
   631		}
   632	
   633		// Get bindings count
   634		cfg, err := loadPersonaConfig(workingDir)
   635		if err == nil && cfg.PersonaBindings != nil {
   636			status.BindingsCount = len(cfg.PersonaBindings)
   637		}
   638	
   639		return status, nil
   640	}
   641	
   642	// personaLoad loads personas into CLAUDE.md
   643	func personaLoad(workingDir string, personas ...string) ([]string, error) {
   644		// Always check if config file exists (new format)
   645		configPath := ".ddx/config.yaml"
   646		if workingDir != "" {
   647			configPath = filepath.Join(workingDir, ".ddx/config.yaml")
   648		}
   649		if _, err := os.Stat(configPath); os.IsNotExist(err) {
   650			return nil, fmt.Errorf("No .ddx/config.yaml configuration found")
   651		}
   652	
   653		// Load config to get persona bindings
   654		cfg, err := loadPersonaConfig(workingDir)
   655		if err != nil {
   656			return nil, fmt.Errorf("failed to load configuration: %w", err)
   657		}
   658	
   659		loader := persona.NewPersonaLoader(workingDir)
   660	
   661		// Read CLAUDE.md if it exists
   662		claudePath := "CLAUDE.md"
   663		if workingDir != "" {
   664			claudePath = filepath.Join(workingDir, "CLAUDE.md")
   665		}
   666	
   667		if _, err := os.Stat(claudePath); err != nil && !os.IsNotExist(err) {
   668			return nil, fmt.Errorf("failed to inspect CLAUDE.md: %w", err)
   669		}
   670	
   671		// Track loaded personas
   672		loadedPersonas := []string{}
   673	
   674		// If specific personas requested, load those; otherwise load all bound personas
   675		var specificPersona *persona.Persona
   676		var boundPersonas map[string]*persona.Persona
   677		if len(personas) > 0 {
   678			// Load specific personas
   679			for _, personaName := range personas {
   680				loadedPersona, err := loader.LoadPersona(personaName)
   681				if err != nil {
   682					if isPersonaNotFound(err) {
   683						return nil, fmt.Errorf("persona '%s' not found", personaName)
   684					}
   685					return nil, err
   686				}
   687				if err := validatePersonaContent(loadedPersona.Content, personaName); err != nil {
   688					return nil, err
   689				}
   690				loadedPersonas = append(loadedPersonas, personaName)
   691				if len(personas) == 1 {
   692					specificPersona = loadedPersona
   693				} else {
   694					if boundPersonas == nil {
   695						boundPersonas = make(map[string]*persona.Persona, len(personas))
   696					}
   697					role := personaName
   698					if len(loadedPersona.Roles) > 0 && strings.TrimSpace(loadedPersona.Roles[0]) != "" {
   699						role = loadedPersona.Roles[0]
   700					}
   701					boundPersonas[role] = loadedPersona
   702				}
   703			}
   704		} else {
   705			// Load all bound personas from config
   706			if cfg.PersonaBindings != nil {
   707				boundPersonas = make(map[string]*persona.Persona, len(cfg.PersonaBindings))
   708				for role, personaName := range cfg.PersonaBindings {
   709					loadedPersona, err := loader.LoadPersona(personaName)
   710					if err != nil {
   711						if isPersonaNotFound(err) {
   712							continue
   713						}
   714						return nil, err
   715					}
   716					if err := validatePersonaContent(loadedPersona.Content, personaName); err != nil {
   717						return nil, err
   718					}
   719					boundPersonas[role] = loadedPersona
   720					loadedPersonas = append(loadedPersonas, personaName)
   721				}
   722			}
   723		}
   724	
   725		if len(loadedPersonas) > 0 {
   726			injector := persona.NewClaudeInjectorWithPath(claudePath)
   727			if err := injector.RemovePersonas(); err != nil {
   728				return nil, err
   729			}
   730			switch {
   731			case specificPersona != nil:
   732				role := specificPersona.Name
   733				if len(specificPersona.Roles) > 0 && strings.TrimSpace(specificPersona.Roles[0]) != "" {
   734					role = specificPersona.Roles[0]
   735				}
   736				if err := injector.InjectPersona(specificPersona, role); err != nil {
   737					return nil, err
   738				}
   739			case len(boundPersonas) > 0:
   740				if err := injector.InjectMultiple(boundPersonas); err != nil {
   741					return nil, err
   742				}
   743			}
   744		}
   745	
   746		return loadedPersonas, nil
   747	}
   748	
   749	func isPersonaNotFound(err error) bool {
   750		var pe *persona.PersonaError
   751		return errors.As(err, &pe) && pe.Type == persona.ErrorPersonaNotFound
   752	}
